import{_ as t,o as e,c as l,ag as i}from"./chunks/framework.DXGyWiRo.js";const r="/media/202503/2025-03-03_100925_7986330.07599608313029738.png",o="/media/202503/2025-03-03_101229_0225600.5747701654704561.png",n="/media/202503/2025-03-03_101314_0511540.3086753437729691.png",s="/media/202503/2025-03-03_101807_6011730.7809167844959928.png",_="/media/202503/2025-03-03_101855_8148110.47965383361228464.png",b=JSON.parse('{"title":"智能体开发","description":"","frontmatter":{"title":"智能体开发"},"headers":[],"relativePath":"custom-biz/skill-studio/agent-dev.md","filePath":"custom-biz/skill-studio/agent-dev.md","lastUpdated":null}'),p={name:"custom-biz/skill-studio/agent-dev.md"};function d(c,a,h,u,m,g){return e(),l("div",null,[...a[0]||(a[0]=[i('<p><strong>目录</strong></p><ol><li>什么是智能体</li><li>智能体创建 2.1. 创建意图 2.2. 编辑语料 2.3. 泛化语料</li></ol><h2 id="什么是智能体" tabindex="-1">什么是智能体 <a class="header-anchor" href="#什么是智能体" aria-label="Permalink to &quot;什么是智能体&quot;">​</a></h2><p>AIUI的智能体（Agent）是指基于大语言模型，能够执行复杂任务以满足用户请求的应用程序。智能体依据用户的语音请求，智能判断交互意图，进行任务分发，支持开发者定制丰富的业务逻辑来执行特定任务，满足用户在特定场景下的一类交互需求。 与技能相比，智能体借助大模型在多个方面实现了智能化。在意图理解、任务分发、任务拆解方面，智能体的表现更为出色。除此之外，平台将支持开发者在智能体中自定义复杂交互逻辑，自由接入外部工具。</p><p>AIUI的智能体当前有以下两种类型：</p><ul><li>官方智能体 AIUI开放平台官方针对通用交互场景打造的精品智能体，如“美食顾问”帮助用户规划菜谱，满足美食问询、烹饪场景的语音问询需求。精品智能体的获取请联系商务/技术支持。</li><li>本地智能体。 调用设备端的应用程序执行任务的智能体。AIUI智能体下发对用户意图的识别结果，具体任务实现逻辑由端侧调用执行。例如创建“投影仪命控”智能体，并事先定义好用户命控的意图。当用户说“这个投影仪画面虚焦了，怎么调整呢”，智能体可识别出用户意图为“对焦”，并下发意图指导端侧完成设备操作。</li></ul><h2 id="智能体创建" tabindex="-1">智能体创建 <a class="header-anchor" href="#智能体创建" aria-label="Permalink to &quot;智能体创建&quot;">​</a></h2><p>在技能工作室的<a href="https://aiui.xfyun.cn/studio/agent" target="_blank" rel="noreferrer">【智能体】</a>中创建，目前仅支持本地智能体类型。</p><p><img src="'+r+'" alt="" title="null"></p><h3 id="_2-1-创建意图" tabindex="-1">2.1. 创建意图 <a class="header-anchor" href="#_2-1-创建意图" aria-label="Permalink to &quot;2.1. 创建意图&quot;">​</a></h3><p>进入智能体后，按照自定义技能下意图创建的方式，构建需要意图。</p><h3 id="注意" tabindex="-1">注意： <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意：&quot;">​</a></h3><p>与自定义技能相比，智能体只提供意图落域能力，不提供填槽抽取能力。</p><p><img src="'+o+'" alt="" title="null"></p><h3 id="_2-2-编辑语料" tabindex="-1">2.2. 编辑语料 <a class="header-anchor" href="#_2-2-编辑语料" aria-label="Permalink to &quot;2.2. 编辑语料&quot;">​</a></h3><p>根据指定的意图，编写用户常用交互说法 <img src="'+n+'" alt="" title="null"></p><h3 id="_2-3-泛化语料" tabindex="-1">2.3. 泛化语料 <a class="header-anchor" href="#_2-3-泛化语料" aria-label="Permalink to &quot;2.3. 泛化语料&quot;">​</a></h3><p>智能体语料编辑，除了可以人工收集编写语料外，也可以让大模型针对已编写好的语料进行自动泛化处理。然后可以点击“一键添加”添加全部，或选择过滤需要的泛化语料单点添加</p><p><img src="'+s+'" alt="" title="null"></p><p><img src="'+_+'" alt="" title="null"></p>',20)])])}const k=t(p,[["render",d]]);export{b as __pageData,k as default};
